# ── HTTP Handler ──────────────────────────────────────────────────────────────
class DashboardHandler(BaseHTTPRequestHandler):
    def log_message(self, format, *args): pass

    def do_GET(self):
        # Statische Dateien aus scripts/static/ (Quill etc.)
        if self.path.startswith('/static/'):
            fname = self.path[8:].split('?')[0]  # Strip /static/ prefix and query
            if fname and '/' not in fname and '..' not in fname:
                static_file = SCRIPTS_DIR / 'static' / fname
                if static_file.exists():
                    ext = fname.rsplit('.', 1)[-1].lower()
                    mime = {'js': 'application/javascript', 'css': 'text/css',
                            'png': 'image/png', 'svg': 'image/svg+xml'}.get(ext, 'application/octet-stream')
                    data = static_file.read_bytes()
                    self._respond(200, mime, data)
                    return
            self._respond(404, 'text/plain', b'Not found')
            return

        if self.path == '/favicon.ico':
            # Minimal valid 1x1 32bpp transparent ICO (70 bytes)
            ico = bytes.fromhex(
                '000001000100'          # ICONDIR: reserved=0, type=1, count=1
                '01010000010020003000000016000000'  # ICONDIRENTRY: 1x1, 0c, 1p, 32bpp, size=48, off=22
                # BITMAPINFOHEADER (40 bytes):
                '28000000'              # biSize=40
                '01000000'              # biWidth=1
                '02000000'              # biHeight=2 (ICO doubles height)
                '0100'                  # biPlanes=1
                '2000'                  # biBitCount=32
                '00000000'              # biCompression=BI_RGB
                '00000000'              # biSizeImage=0
                '00000000'              # biXPelsPerMeter=0
                '00000000'              # biYPelsPerMeter=0
                '00000000'              # biClrUsed=0
                '00000000'              # biClrImportant=0
                '00000000'              # XOR pixel: BGRA fully transparent
                '00000000'              # AND mask: DWORD-padded
            )
            self._respond(200, 'image/x-icon', ico)

        elif self.path.startswith('/oauth/google/callback'):
            self._handle_google_oauth_callback()

        elif self.path in ('/', '/dashboard', '/index.html'):
            html = generate_html()
            self._html(html)

        elif self.path == '/partner':
            pv_path = SCRIPTS_DIR.parent / 'partner_view.html'
            try:
                html = pv_path.read_text('utf-8')
                self._html(html)
            except FileNotFoundError:
                self.send_error(404, 'partner_view.html nicht gefunden')

        elif self.path == '/api/partner/get-token':
            try:
                secs_path = SCRIPTS_DIR / 'secrets.json'
                secs = json.loads(secs_path.read_bytes()) if secs_path.exists() else {}
                token = secs.get('partner_feedback_token') or secs.get('github_pat') or ''
                # Token maskieren: nur Prefix zeigen, Rest als *
                masked = (token[:12] + '****') if len(token) > 12 else ('****' if token else '')
                self._json({'ok': True, 'token': token, 'masked': masked, 'has_token': bool(token)})
            except Exception as e:
                self._json({'ok': False, 'error': str(e)})

        elif self.path == '/api/tasks/open':
            db = get_db()
            rows = db.execute("SELECT * FROM tasks WHERE status='offen' ORDER BY prioritaet DESC, datum_mail DESC").fetchall()
            db.close()
            self._json([{k:v for k,v in dict(r).items() if k in
                ('id','typ','kategorie','titel','kunden_email','prioritaet','datum_mail','zusammenfassung','absender_rolle')}
                for r in rows])

        elif self.path == '/api/tasks/closed':
            db = get_db()
            rows = db.execute("""SELECT * FROM tasks WHERE status IN ('erledigt','ignorieren')
                ORDER BY aktualisiert_am DESC LIMIT 50""").fetchall()
            db.close()
            self._json([dict(r) for r in rows])

        elif self.path == '/api/corrections':
            db = get_db()
            try:
                rows = db.execute("SELECT * FROM corrections ORDER BY erstellt_am DESC LIMIT 50").fetchall()
                self._json([dict(r) for r in rows])
            except:
                self._json([])
            finally:
                db.close()

        elif self.path.startswith('/api/loeschhistorie'):
            db = get_db()
            try:
                rows = db.execute("""
                    SELECT id, geloescht_am, task_id, konto, absender, betreff,
                           datum_mail, anhaenge_info, grund, referenz_task_id, referenz_konto
                    FROM loeschhistorie
                    ORDER BY geloescht_am DESC LIMIT 100
                """).fetchall()
                self._json([dict(r) for r in rows])
            except:
                self._json([])
            finally:
                db.close()

        elif self.path == '/api/geschaeft':
            db = get_db()
            try:
                rows = db.execute("SELECT * FROM geschaeft ORDER BY datum DESC LIMIT 100").fetchall()
                self._json([dict(r) for r in rows])
            except:
                self._json([])
            finally:
                db.close()

        elif self.path == '/api/organisation':
            db = get_db()
            try:
                rows = db.execute("SELECT * FROM organisation ORDER BY datum_erkannt DESC").fetchall()
                self._json([dict(r) for r in rows])
            except:
                self._json([])
            finally:
                db.close()

        elif self.path == '/api/wissen':
            db = get_db()
            try:
                rows = db.execute("SELECT * FROM wissen_regeln ORDER BY kategorie, id").fetchall()
                self._json([dict(r) for r in rows])
            except:
                self._json([])
            finally:
                db.close()

        elif self.path.startswith('/api/file?'):
            self._serve_file()

        elif self.path.startswith('/api/attachments?'):
            self._list_attachments()

        elif self.path.startswith('/api/mail/read?'):
            self._read_mail()

        elif self.path.startswith('/api/mail/kira-kontext?'):
            self._api_mail_kira_kontext()

        elif self.path == '/api/mail/folders':
            self._api_mail_folders()

        elif self.path == '/api/mail/konten':
            self._api_mail_konten()

        elif self.path.startswith('/api/mail/oauth/status'):
            self._api_mail_oauth_status()

        elif self.path.startswith('/api/mail/favorites'):
            self._api_mail_favorites_get()

        elif self.path == '/api/mail/snooze/count':
            self._api_mail_snooze_count()

        elif self.path.startswith('/api/mail/combined/konten'):
            self._api_mail_combined_konten_get()

        elif self.path.startswith('/api/mail/combined'):
            self._api_mail_combined()

        elif self.path.startswith('/api/mail/list'):
            self._api_mail_list()

        elif self.path.startswith('/api/mail/thread'):
            self._api_mail_thread()

        elif self.path.startswith('/api/mail/mark-read'):
            qs = urllib.parse.parse_qs(urllib.parse.urlparse(self.path).query)
            msg_id = qs.get('message_id', [''])[0]
            if msg_id:
                try:
                    conn = sqlite3.connect(str(MAIL_INDEX_DB))
                    conn.execute("UPDATE mails SET gelesen=1 WHERE message_id=?", (msg_id,))
                    conn.commit()
                    conn.close()
                    self._json({'ok': True})
                except Exception as e:
                    self._json({'ok': False, 'error': str(e)})
            else:
                self._json({'ok': False, 'error': 'missing message_id'})

        elif self.path == '/api/mail/archiv/status':
            self._api_mail_archiv_status()

        elif self.path == '/api/mail/archiv/reindex/progress':
            self._api_mail_archiv_reindex_progress()

        elif self.path.startswith('/api/ausgangsrechnungen'):
            self._api_ausgangsrechnungen()

        elif self.path.startswith('/api/angebote'):
            self._api_angebote()

        # ── Lexware Office GET-Routing (session-eee) ──
        elif self.path == '/api/lexware/status':
            self._api_lexware_status()

        elif self.path == '/api/lexware/belege':
            self._api_lexware_belege_list()

        elif self.path == '/api/lexware/kontakte':
            self._api_lexware_kontakte_list()

        elif self.path == '/api/lexware/eingangsbelege':
            self._api_lexware_eingangsbelege_list()

        elif self.path.startswith('/api/lexware/beleg/'):
            lex_id = urllib.parse.unquote(self.path.split('/api/lexware/beleg/')[1])
            self._api_lexware_beleg(lex_id)

        elif self.path.startswith('/api/lexware/artikel/'):
            lex_id = urllib.parse.unquote(self.path.split('/api/lexware/artikel/')[1])
            self._api_lexware_artikel(lex_id)

        elif self.path.startswith('/api/lexware/kontakt/') and not self.path.endswith('/update'):
            lex_id = urllib.parse.unquote(self.path.split('/api/lexware/kontakt/')[1])
            self._api_lexware_kontakt(lex_id)

        elif self.path.startswith('/api/lexware/eingangsbeleg/') and not self.path.endswith('/status') and not self.path.endswith('/kira-klassifizieren'):
            try:
                beleg_id = int(self.path.split('/api/lexware/eingangsbeleg/')[1].split('/')[0])
            except ValueError:
                beleg_id = 0
            self._api_lexware_eingangsbeleg(beleg_id)

        # ── Lexware Office GET-Routing (session-fff) ──
        elif self.path == '/api/lexware/cockpit':
            self._api_lexware_cockpit()

        elif self.path == '/api/lexware/regeln':
            self._api_lexware_regeln()

        elif self.path == '/api/lexware/zahlungen':
            self._api_lexware_zahlungen()

        elif self.path == '/api/lexware/dateien':
            self._api_lexware_dateien()

        elif self.path == '/api/lexware/diagnose':
            self._api_lexware_diagnose()

        elif self.path == '/api/kira/insights':
            self._api_kira_insights()

        elif self.path.startswith('/api/kira/aktivitaeten'):
            self._api_kira_aktivitaeten()

        elif self.path == '/api/kira/proaktiv/status':
            self._api_kira_proaktiv_status()

        elif self.path == '/api/kira/background-status':
            self._api_kira_background_status()

        elif self.path.startswith('/api/kira/activity-feed'):
            self._api_kira_activity_feed()

        elif self.path == '/api/zusagen':
            self._api_zusagen_list()

        elif self.path == '/api/kira/circuit_breaker':
            self._api_kira_circuit_breaker_get()

        elif self.path.startswith('/api/kira/termine'):
            self._api_kira_termine()

        elif self.path == '/api/leistungen':
            try:
                from task_manager import get_active_profile
                profil = get_active_profile()
                self._json(profil.get("leistungen", {"katalog": [], "nicht_leistungen": []}))
            except Exception as e:
                self._json({"error": str(e)})

        elif self.path == '/api/artikel':
            # Vereinheitlichte Artikelliste (Lexware + Manuell)
            db = get_db()
            try:
                result = []
                try:
                    for r in db.execute("SELECT id, lexware_id, name, beschreibung, einheit, netto_preis, steuer_satz, typ, last_sync FROM lexware_artikel ORDER BY name").fetchall():
                        result.append({**dict(r), "herkunft": "lexware", "editierbar": False})
                except Exception:
                    pass
                try:
                    for r in db.execute("SELECT id, lexware_id, name, beschreibung, einheit, netto_preis, steuer_satz, typ, kategorie, erstellt_ts, geaendert_ts FROM manuelle_artikel WHERE aktiv=1 ORDER BY name").fetchall():
                        result.append({**dict(r), "herkunft": "manuell", "editierbar": True})
                except Exception:
                    pass
                self._json({"ok": True, "artikel": result, "count": len(result)})
            finally:
                db.close()

        elif self.path.startswith('/api/artikel/') and '/preishistorie' in self.path:
            # GET /api/artikel/{id}/preishistorie
            try:
                art_id = int(self.path.split('/api/artikel/')[1].split('/')[0])
                db = get_db()
                try:
                    rows = db.execute(
                        "SELECT name, beschreibung, netto_preis, einheit, snapshot_ts, sync_event, diff_pct, artikel_quelle, aenderung_typ "
                        "FROM artikel_preishistorie WHERE artikel_id=? ORDER BY snapshot_ts DESC LIMIT 100",
                        (art_id,)
                    ).fetchall()
                    self._json({"ok": True, "historie": [dict(r) for r in rows], "count": len(rows)})
                finally:
                    db.close()
            except Exception as e:
                self._json({"ok": False, "error": str(e)})

        elif self.path == '/api/artikel/statistik':
            # Aggregierte Preis-Statistiken
            db = get_db()
            try:
                stats = {}
                try:
                    stats["aenderungen_30d"] = db.execute(
                        "SELECT COUNT(*) FROM artikel_preishistorie WHERE snapshot_ts >= datetime('now', '-30 days')"
                    ).fetchone()[0]
                    stats["artikel_lexware"] = db.execute("SELECT COUNT(*) FROM lexware_artikel").fetchone()[0]
                except Exception:
                    stats["artikel_lexware"] = 0
                    stats["aenderungen_30d"] = 0
                try:
                    stats["artikel_manuell"] = db.execute("SELECT COUNT(*) FROM manuelle_artikel WHERE aktiv=1").fetchone()[0]
                except Exception:
                    stats["artikel_manuell"] = 0
                self._json({"ok": True, **stats})
            finally:
                db.close()

        elif self.path == '/api/artikel/historie' or self.path.startswith('/api/artikel/historie?'):
            # GET /api/artikel/historie — Gesamte Änderungshistorie
            db = get_db()
            try:
                rows = db.execute(
                    "SELECT artikel_id, name, beschreibung, netto_preis, einheit, snapshot_ts, "
                    "sync_event, diff_pct, artikel_quelle, aenderung_typ "
                    "FROM artikel_preishistorie ORDER BY snapshot_ts DESC LIMIT 500"
                ).fetchall()
                self._json({"ok": True, "historie": [dict(r) for r in rows], "count": len(rows)})
            except Exception as e:
                self._json({"ok": False, "error": str(e)})
            finally:
                db.close()

        elif self.path.startswith('/api/artikel/historie/export'):
            # GET /api/artikel/historie/export?format=csv — CSV-Export der Änderungshistorie
            db = get_db()
            try:
                rows = db.execute(
                    "SELECT snapshot_ts, name, beschreibung, netto_preis, einheit, aenderung_typ, "
                    "diff_pct, artikel_quelle, sync_event "
                    "FROM artikel_preishistorie ORDER BY snapshot_ts DESC"
                ).fetchall()
                lines = ["Datum;Artikel;Beschreibung;Netto-Preis;Einheit;Änderungstyp;Änderung %;Quelle;Event"]
                for r in rows:
                    rd = dict(r)
                    lines.append(";".join(str(rd.get(k, "")) for k in [
                        "snapshot_ts", "name", "beschreibung", "netto_preis", "einheit",
                        "aenderung_typ", "diff_pct", "artikel_quelle", "sync_event"
                    ]))
                data = "\n".join(lines).encode("utf-8-sig")
                self.send_response(200)
                self.send_header("Content-Type", "text/csv; charset=utf-8")
                self.send_header("Content-Disposition", 'attachment; filename="artikel_historie.csv"')
                self.send_header("Content-Length", str(len(data)))
                self.end_headers()
                self.wfile.write(data)
            except Exception as e:
                self._json({"ok": False, "error": str(e)})
            finally:
                db.close()

        elif self.path.startswith('/api/artikel/export'):
            # CSV/JSON-Export aller Artikel
            fmt = "csv"
            if "?" in self.path:
                qs = urllib.parse.parse_qs(self.path.split("?")[1])
                fmt = qs.get("format", ["csv"])[0]
            db = get_db()
            try:
                rows = []
                for tbl, herk in [("lexware_artikel", "lexware"), ("manuelle_artikel", "manuell")]:
                    try:
                        for r in db.execute(f"SELECT name, beschreibung, einheit, netto_preis, steuer_satz, typ FROM {tbl}{' WHERE aktiv=1' if tbl == 'manuelle_artikel' else ''} ORDER BY name").fetchall():
                            rows.append({**dict(r), "herkunft": herk})
                    except Exception:
                        pass
                if fmt == "json":
                    data = json.dumps(rows, ensure_ascii=False, indent=2).encode("utf-8")
                    self.send_response(200)
                    self.send_header("Content-Type", "application/json; charset=utf-8")
                    self.send_header("Content-Disposition", 'attachment; filename="artikel_export.json"')
                    self.send_header("Content-Length", str(len(data)))
                    self.end_headers()
                    self.wfile.write(data)
                else:
                    lines = ["name;beschreibung;einheit;netto_preis;steuer_satz;typ;herkunft"]
                    for r in rows:
                        lines.append(";".join(str(r.get(k, "")) for k in ["name", "beschreibung", "einheit", "netto_preis", "steuer_satz", "typ", "herkunft"]))
                    data = "\n".join(lines).encode("utf-8-sig")
                    self.send_response(200)
                    self.send_header("Content-Type", "text/csv; charset=utf-8")
                    self.send_header("Content-Disposition", 'attachment; filename="artikel_export.csv"')
                    self.send_header("Content-Length", str(len(data)))
                    self.end_headers()
                    self.wfile.write(data)
            finally:
                db.close()

        elif self.path == '/api/config/export':
            try:
                cfg  = json.loads((SCRIPTS_DIR / "config.json").read_text('utf-8'))
                data = json.dumps(cfg, ensure_ascii=False, indent=2).encode('utf-8')
                self.send_response(200)
                self.send_header('Content-Type', 'application/json; charset=utf-8')
                self.send_header('Content-Disposition', 'attachment; filename="kira_config.json"')
                self.send_header('Content-Length', str(len(data)))
                self.end_headers()
                self.wfile.write(data)
            except Exception as e:
                self._json({'ok': False, 'error': str(e)})

        elif self.path.startswith('/api/export/'):
            self._api_dokument_export()

        elif self.path == '/api/belegvorlagen':
            self._api_belegvorlagen_list()

        elif self.path.startswith('/api/zeiterfassung'):
            self._api_zeiterfassung_list()

        elif self.path == '/api/monitor/status':
            self._json(get_monitor_status())

        elif self.path == '/api/server/check-update':
            changed = []
            for fp_str, orig_mt in _STARTUP_MTIMES.items():
                try:
                    cur = Path(fp_str).stat().st_mtime
                    if cur != orig_mt:
                        changed.append(Path(fp_str).name)
                except Exception:
                    pass
            self._json({"restart_needed": _RESTART_NEEDED or len(changed) > 0, "changed_files": changed})

        elif self.path.startswith('/api/aktivitaeten'):
            qs = urllib.parse.parse_qs(urllib.parse.urlparse(self.path).query)
            limit   = int(qs.get('limit',  ['200'])[0])
            offset  = int(qs.get('offset', ['0'])[0])
            bereich = qs.get('bereich', [''])[0]
            status  = qs.get('status',  [''])[0]
            entries = alog_entries(min(limit,500), offset, bereich or None, status or None)
            stats   = alog_stats()
            self._json({'entries': entries, 'stats': stats})

        elif self.path == '/api/dashboard/live':
            try:
                data = _dashboard_data()
                self._json(data)
            except Exception as ex:
                self._json({'error': str(ex), 'kpis': [], 'briefing': {}, 'actions': [], 'feed': [], 'termine': [], 'geschaeft': [], 'vorgaenge': {'items': [], 'total': 0}, 'signale': [], 'sent': [], 'sparkline': [], 'mi_stats': {}, 'freigaben': 0, 'ts': ''})

        elif self.path == '/api/dashboard/widgets':
            try:
                data = get_dashboard_widgets()
                self._json(data)
            except Exception as ex:
                self._json({'weather': None, 'news': [], 'newsletter': None, 'ts': '', '_err': str(ex)})

        elif self.path.startswith('/api/runtime/events'):
            qs          = urllib.parse.parse_qs(urllib.parse.urlparse(self.path).query)
            limit       = min(int(qs.get('limit',  ['50'])[0]),  500)
            offset      = int(qs.get('offset', ['0'])[0])
            event_type  = qs.get('event_type', [''])[0]
            modul       = qs.get('modul',      [''])[0]
            status      = qs.get('status',     [''])[0]
            action      = qs.get('action',     [''])[0]
            search      = qs.get('search',     [''])[0]
            session_id  = qs.get('session_id', [''])[0]
            try:
                data = rlog_get(limit=limit, offset=offset,
                                event_type=event_type or None, modul=modul or None,
                                status=status or None, action=action or None,
                                search=search or None, session_id=session_id or None)
            except Exception as ex:
                data = {'entries': [], 'total': 0, '_err': str(ex)}
            self._json(data)

        elif self.path == '/api/runtime/stats':
            try:
                self._json(rlog_stats())
            except Exception as ex:
                self._json({'error': str(ex)})

        elif self.path.startswith('/api/runtime/event/') and self.path.endswith('/payload'):
            eid = self.path[len('/api/runtime/event/'):-len('/payload')]
            try:
                self._json(rlog_payload(eid))
            except Exception as ex:
                self._json({'error': str(ex)})

        elif self.path.startswith('/api/changelog'):
            qs       = urllib.parse.parse_qs(urllib.parse.urlparse(self.path).query)
