    def _api_kira_background_status(self):
        """GET /api/kira/background-status — Alle Hintergrund-Prozesse zusammengefasst."""
        jobs = []
        # 1. Reklassifizierung
        try:
            from daily_check import get_reclassify_progress
            rc = get_reclassify_progress()
            if rc.get("running"):
                pct = round(100 * rc.get("geprueft", 0) / max(rc.get("gesamt", 1), 1))
                jobs.append({"id": "reclassify", "label": "Reklassifizierung",
                             "pct": pct, "detail": f'{rc["geprueft"]}/{rc["gesamt"]}'})
            elif rc.get("paused"):
                jobs.append({"id": "reclassify", "label": "Reklassifizierung",
                             "pct": -1, "detail": "Pausiert"})
        except Exception:
            pass
        # 2. Nachklassifizierung (recheck_mails)
        try:
            from daily_check import get_recheck_progress
            rk = get_recheck_progress()
            if rk.get("laeuft"):
                pct = round(100 * rk.get("geprueft", 0) / max(rk.get("gesamt", 1), 1))
                jobs.append({"id": "recheck", "label": "Nachklassifizierung",
                             "pct": pct, "detail": f'{rk["geprueft"]}/{rk["gesamt"]}'})
        except Exception:
            pass
        # 3. Qualifizierung
        try:
            from daily_check import get_qualify_progress
            qp = get_qualify_progress()
            if qp.get("laeuft"):
                pct = round(100 * qp.get("geprueft", 0) / max(qp.get("gesamt", 1), 1))
                jobs.append({"id": "qualify", "label": "Qualifizierung",
                             "pct": pct, "detail": f'{qp["geprueft"]}/{qp["gesamt"]}'})
            elif qp.get("pausiert"):
                jobs.append({"id": "qualify", "label": "Qualifizierung",
                             "pct": -1, "detail": "Pausiert"})
        except Exception:
            pass
        # 4. Mail-Monitor (aktiver Abruf)
        try:
            from mail_monitor import get_monitor_status
            ms = get_monitor_status()
            if ms.get("running"):
                jobs.append({"id": "mail_monitor", "label": "Mail-Abruf",
                             "pct": -1, "detail": ms.get("aktuell", "läuft")})
        except Exception:
            pass
        self._json({"ok": True, "jobs": jobs, "active": len(jobs) > 0})

    def _api_zusagen_list(self):
        """GET /api/zusagen — Alle offenen Zusagen/Commitments."""
        try:
            db = sqlite3.connect(str(TASKS_DB))
            db.row_factory = sqlite3.Row
            # Tabelle existiert?
            _tbl = db.execute("SELECT name FROM sqlite_master WHERE type='table' AND name='mail_commitments'").fetchone()
            if not _tbl:
                self._json({"ok": True, "zusagen": [], "total": 0})
                return
            rows = db.execute("""
                SELECT id, mail_message_id, typ, text, datum_faellig, datum_erinnerung,
                       prioritaet, status, absender, betreff, konto_label, erstellt_am, erledigt_am
                FROM mail_commitments
                WHERE status='offen'
                ORDER BY CASE WHEN datum_faellig IS NULL THEN '9999' ELSE datum_faellig END ASC
                LIMIT 50
            """).fetchall()
            zusagen = [dict(r) for r in rows]
            total = db.execute("SELECT COUNT(*) FROM mail_commitments WHERE status='offen'").fetchone()[0]
            db.close()
            self._json({"ok": True, "zusagen": zusagen, "total": total})
        except Exception as e:
            self._json({"ok": False, "error": str(e)})

    def _api_kira_activity_feed(self):
        """GET /api/kira/activity-feed — Individuelle Activity-Items für den Drawer (Win11 Widget-Style)."""
        try:
            # Revival-Tage aus Config (einstellbar)
            try:
                cfg = json.loads((SCRIPTS_DIR / 'config.json').read_text('utf-8'))
                revival_tage = int(cfg.get('activity_feed', {}).get('revival_tage', 7))
            except Exception:
                revival_tage = 7

            db = sqlite3.connect(str(TASKS_DB))
            db.row_factory = sqlite3.Row
            today = datetime.now().date()
            now = datetime.now()

            # Dismissed Keys laden (nur nicht-revived)
            dismissed = set()
            try:
                for r in db.execute("SELECT item_key, dismissed_at FROM kira_activity_dismissed WHERE revived_at IS NULL"):
                    dismissed.add(r["item_key"])
            except Exception:
                pass

            def _check_revival(key, revival_days):
                """Prüft ob ein dismissed Item revived werden soll. Gibt True zurück wenn Item angezeigt werden darf."""
                if key not in dismissed:
                    return True
                try:
                    row = db.execute("SELECT dismissed_at FROM kira_activity_dismissed WHERE item_key=?", (key,)).fetchone()
                    if row:
                        dism_dt = datetime.fromisoformat(row["dismissed_at"])
                        if (now - dism_dt).days >= revival_days:
                            db.execute("UPDATE kira_activity_dismissed SET revived_at=? WHERE item_key=?",
                                       (now.isoformat(), key))
                            db.commit()
                            dismissed.discard(key)
                            return True
                except Exception:
                    pass
                return False

            items = []

            # ── 1. Überfällige Rechnungen (einzeln) ──
            re_count = 0
            try:
                for r in db.execute("""
                    SELECT re_nummer, datum, kunde_name, betrag_brutto, mahnung_count
                    FROM ausgangsrechnungen WHERE status='offen' AND datum IS NOT NULL
                    ORDER BY datum ASC
                """):
                    try:
                        re_datum = datetime.strptime(str(r["datum"])[:10], "%Y-%m-%d").date()
                        tage = (today - re_datum).days
                    except Exception:
                        continue
                    if tage < 14:
                        continue
                    key = f"re:{r['re_nummer']}"
                    if not _check_revival(key, revival_tage):
                        continue
                    betrag = r["betrag_brutto"] or 0
                    kunde = r["kunde_name"] or "Unbekannt"
                    is_urgent = tage >= 30
                    if is_urgent:
                        kira_says = f"Wartet seit {tage} Tagen. Mahnung vorbereiten?"
                    else:
                        kira_says = "Noch keine Zahlung eingegangen."
                    # Nur die schlimmste Rechnung bekommt full-width
                    items.append({
                        "key": key, "type": "rechnung",
                        "priority": "urgent" if is_urgent else "high",
                        "size": "full" if (is_urgent and re_count == 0) else "half",
                        "title": str(r["re_nummer"]),
                        "subtitle": kunde,
                        "detail": f"{betrag:,.2f} EUR \u00b7 {tage}d".replace(",", "X").replace(".", ",").replace("X", "."),
                        "kira_says": kira_says,
                        "accent": "#ef4444" if is_urgent else "#f59e0b",
                        "action": {"type": "navigate", "target": "showPanel('geschaeft')"},
                        "ts": str(r["datum"])[:10],
                    })
                    re_count += 1
            except Exception:
                pass

            # ── 2. Termine & Fristen (aus organisation-Tabelle) ──
            termine_count = 0
            try:
                _ORG_TYP = {"termin": "Termin", "frist": "Frist", "rueckruf": "Rückruf"}
                for r in db.execute("""
                    SELECT id, typ, datum_erkannt, beschreibung, kunden_email
                    FROM organisation
                    WHERE datum_erkannt >= date('now', '-1 day') AND datum_erkannt <= date('now', '+14 days')
                    ORDER BY datum_erkannt ASC LIMIT 10
                """):
                    key = f"termin:{r['id']}"
                    if key in dismissed:
                        continue
                    dat = str(r["datum_erkannt"] or "")[:10]
                    typ = _ORG_TYP.get(r["typ"] or "", (r["typ"] or "Termin").title())
                    beschr = (r["beschreibung"] or "")[:60]
                    diff = 999
                    try:
                        d = datetime.strptime(dat, "%Y-%m-%d").date()
                        diff = (d - today).days
                    except Exception:
                        pass
                    if diff < 0:
                        prio = "urgent"
                        detail = f"Überfällig seit {abs(diff)}d"
                    elif diff == 0:
                        prio = "high"
                        detail = "Heute"
                    elif diff <= 2:
                        prio = "high"
                        detail = f"In {diff} Tag{'en' if diff > 1 else ''}"
                    else:
                        prio = "normal"
                        detail = dat
                    items.append({
                        "key": key, "type": "termin",
                        "priority": prio,
                        "size": "full" if diff <= 0 else "half",
                        "title": f"{typ}: {beschr[:35]}" if beschr else typ,
                        "subtitle": r["kunden_email"] or "",
                        "detail": detail,
                        "kira_says": "Überfällig — dringend erledigen!" if diff < 0 else ("Steht heute an." if diff == 0 else ""),
                        "accent": "#ef4444" if diff <= 0 else ("#f59e0b" if diff <= 2 else "#3b82f6"),
                        "action": {"type": "navigate", "target": "showPanel('organisation')"},
                        "ts": dat,
                    })
                    termine_count += 1
            except Exception:
                pass

            # ── 3. Offene Angebote ohne Rückmeldung (>14 Tage) ──
            try:
                for r in db.execute("""
                    SELECT a_nummer, kunde_name, erstellt, betrag_geschaetzt
                    FROM angebote WHERE status='offen' AND erstellt IS NOT NULL
                    ORDER BY erstellt ASC LIMIT 5
                """):
                    try:
                        d = datetime.strptime(str(r["erstellt"])[:10], "%Y-%m-%d")
                        tage = (now - d).days
                    except Exception:
                        continue
                    if tage < 14:
                        continue
                    key = f"angebot:{r['a_nummer']}"
                    if not _check_revival(key, revival_tage):
                        continue
                    kunde = r["kunde_name"] or "?"
                    betrag = r["betrag_geschaetzt"] or 0
                    items.append({
                        "key": key, "type": "angebot",
                        "priority": "normal",
                        "size": "half",
                        "title": str(r["a_nummer"] or "Angebot"),
                        "subtitle": kunde[:30],
                        "detail": f"{tage}d ohne Rückmeldung" + (f" \u00b7 {betrag:,.0f} EUR".replace(",", ".") if betrag else ""),
                        "kira_says": "Nachfassen?",
                        "accent": "#6366f1",
                        "action": {"type": "navigate", "target": "showPanel('geschaeft');setTimeout(()=>showGeschTab('angebote'),100)"},
                        "ts": str(r["erstellt"])[:10],
                    })
            except Exception:
                pass

            # ── 4. Neue Leads (letzte 48h, einzeln) ──
            try:
                seit_48h = (now - timedelta(hours=48)).strftime("%Y-%m-%d %H:%M")
                for r in db.execute("""
                    SELECT id, titel, kunde_name, erstellt_am, kategorie
                    FROM tasks
                    WHERE typ IN ('anfrage', 'lead', 'anfrage_lead')
                      AND erstellt_am >= ? AND status NOT IN ('erledigt', 'archiviert', 'ignoriert')
                    ORDER BY erstellt_am DESC
                """, (seit_48h,)):
                    key = f"lead:{r['id']}"
                    if key in dismissed:
                        continue
                    kunde = r["kunde_name"] or r["titel"] or f"Anfrage #{r['id']}"
                    items.append({
                        "key": key, "type": "lead",
                        "priority": "normal",
                        "size": "half",
                        "title": kunde[:35],
                        "subtitle": r["kategorie"] or "Neue Anfrage",
                        "detail": str(r["erstellt_am"] or "")[:16],
                        "kira_says": f"Angebot erstellen?",
                        "accent": "#3b82f6",
                        "action": {"type": "navigate", "target": "showPanel('kommunikation')"},
                        "ts": str(r["erstellt_am"] or "")[:10],
                    })
            except Exception:
                pass

            # ── 5. Pending Freigaben (einzeln) ──
            try:
                for r in db.execute("""
                    SELECT id, an, betreff, erstellt_am
                    FROM mail_approve_queue WHERE status='pending'
                    ORDER BY erstellt_am ASC
                """):
                    key = f"freigabe:{r['id']}"
                    if not _check_revival(key, 1):  # Freigaben nach 1 Tag reviven
                        continue
                    items.append({
                        "key": key, "type": "freigabe",
                        "priority": "high",
                        "size": "half",
                        "title": (r["betreff"] or "Mail-Entwurf")[:40],
                        "subtitle": f"An: {r['an'] or '?'}",
                        "detail": str(r["erstellt_am"] or "")[:16],
                        "kira_says": "Wartet auf dein OK.",
                        "accent": "#8b5cf6",
                        "action": {"type": "navigate", "target": "pfKiraAusgangOpen()"},
                        "ts": str(r["erstellt_am"] or "")[:10],
                    })
            except Exception:
                pass

            # ── 6. Case-Engine Signale (angezeigt=0) ──
            try:
                for r in db.execute("""
                    SELECT id, stufe, titel, nachricht, erstellt_am
                    FROM vorgang_signals WHERE angezeigt=0
                    ORDER BY stufe DESC, erstellt_am DESC LIMIT 8
                """):
                    key = f"signal:{r['id']}"
                    if key in dismissed:
                        continue
                    is_c = r["stufe"] == "C"
                    items.append({
                        "key": key, "type": "signal",
                        "priority": "urgent" if is_c else "high",
                        "size": "full" if is_c else "half",
                        "title": (r["titel"] or "Signal")[:45],
                        "subtitle": "",
                        "detail": (r["nachricht"] or "")[:80],
                        "kira_says": "",
                        "accent": "#ef4444" if is_c else "#f59e0b",
                        "action": None,
                        "ts": str(r["erstellt_am"] or "")[:10],
                    })
            except Exception:
                pass

            # ── 7. Offene Tasks mit Frist (Tasks mit deadline in nächsten 7 Tagen) ──
            try:
                for r in db.execute("""
                    SELECT id, titel, kunde_name, deadline, prioritaet
                    FROM tasks
                    WHERE deadline IS NOT NULL AND deadline != ''
                      AND deadline >= date('now', '-1 day') AND deadline <= date('now', '+7 days')
                      AND status NOT IN ('erledigt', 'archiviert', 'ignoriert')
                    ORDER BY deadline ASC LIMIT 6
                """):
                    key = f"task-frist:{r['id']}"
                    if key in dismissed:
                        continue
                    dl = str(r["deadline"] or "")[:10]
                    try:
                        diff = (datetime.strptime(dl, "%Y-%m-%d").date() - today).days
                    except Exception:
                        diff = 99
                    titel = r["titel"] or r["kunde_name"] or f"Aufgabe #{r['id']}"
                    items.append({
                        "key": key, "type": "frist",
                        "priority": "urgent" if diff < 0 else ("high" if diff <= 1 else "normal"),
                        "size": "half",
                        "title": titel[:35],
                        "subtitle": r["kunde_name"] or "",
                        "detail": "Überfällig!" if diff < 0 else ("Heute fällig" if diff == 0 else f"Frist in {diff}d"),
                        "kira_says": "",
                        "accent": "#ef4444" if diff < 0 else ("#f59e0b" if diff <= 1 else "#6366f1"),
                        "action": {"type": "navigate", "target": "showPanel('kommunikation')"},
                        "ts": dl,
                    })
            except Exception:
                pass

            # ── 8. Offene Zusagen + fällige Commitments ──
            zusagen_count = 0
            try:
                # Tabelle existiert?
                _tbl = db.execute("SELECT name FROM sqlite_master WHERE type='table' AND name='mail_commitments'").fetchone()
                if _tbl:
                    for r in db.execute("""
                        SELECT id, typ, text, datum_faellig, absender, betreff
                        FROM mail_commitments
                        WHERE status='offen' AND datum_faellig IS NOT NULL
                          AND datum_faellig <= date('now', '+7 days')
                        ORDER BY datum_faellig ASC LIMIT 8
                    """):
                        key = f"zusage:{r['id']}"
                        if key in dismissed:
                            continue
                        dat = str(r["datum_faellig"] or "")[:10]
                        try:
                            diff = (datetime.strptime(dat, "%Y-%m-%d").date() - today).days
                        except Exception:
                            diff = 99
                        absender_kurz = (r["absender"] or "").split("<")[0].strip()[:30]
                        text_kurz = (r["text"] or "")[:60]
                        if diff < 0:
                            kira_text = f"Seit {abs(diff)} Tag(en) \u00fcberf\u00e4llig!"
                            prio = "urgent"
                            accent = "#ef4444"
                        elif diff == 0:
                            kira_text = "Heute f\u00e4llig."
                            prio = "high"
                            accent = "#f59e0b"
                        else:
                            kira_text = f"In {diff} Tag(en)."
                            prio = "normal"
                            accent = "#f97316"
                        items.append({{
                            "key": key, "type": "zusage",
                            "priority": prio,
                            "size": "half",
                            "title": f"\u23f0 {{text_kurz}}" if text_kurz else f"\u23f0 Zusage an {{absender_kurz}}",
                            "subtitle": absender_kurz,
                            "detail": dat,
                            "kira_says": kira_text,
                            "accent": accent,
                            "action": {{"type": "navigate", "target": "showPanel('kommunikation')"}},
                            "ts": dat,
                        }})
                        zusagen_count += 1
            except Exception:
                pass

            db.close()

            # ── Status-Kacheln (positiv — wenn bestimmte Bereiche leer sind) ──
            if termine_count == 0:
                items.append({
                    "key": "_status:termine", "type": "status",
                    "priority": "info", "size": "half",
                    "title": "Keine Termine",
                    "subtitle": "Nächste 14 Tage frei",
                    "detail": "", "kira_says": "",
                    "accent": "#22c55e", "action": None, "ts": "zzz",
                })
            if re_count == 0:
                items.append({
                    "key": "_status:rechnungen", "type": "status",
                    "priority": "info", "size": "half",
                    "title": "Rechnungen OK",
                    "subtitle": "Keine überfälligen Rechnungen",
                    "detail": "", "kira_says": "",
                    "accent": "#22c55e", "action": None, "ts": "zzz",
                })

            # Sortieren: urgent → high → normal → info (status)
            prio_order = {"urgent": 0, "high": 1, "normal": 2, "info": 3}
            items.sort(key=lambda x: (prio_order.get(x["priority"], 9), x.get("ts", "") or ""))

            # Begrüßung
            h = now.hour
            if h < 12:
                gruss = "Guten Morgen"
            elif h < 17:
                gruss = "Hallo"
            else:
                gruss = "Guten Abend"
            # Zähle nur echte Action-Items (nicht Status-Kacheln)
            n_real = len([i for i in items if i["priority"] != "info"])
            n = len(items)
            if n_real == 0:
                greeting = f"{gruss} Kai \u2014 alles im Griff."
            elif n_real == 1:
                greeting = f"{gruss} Kai, eine Sache die du wissen solltest:"
            else:
                greeting = f"{gruss} Kai, {n_real} Dinge die du wissen solltest:"

            self._json({
                "ok": True,
                "greeting": greeting,
                "items": items,
                "total": n_real,
                "ts": now.isoformat(),
            })
        except Exception as e:
            self._json({"ok": False, "error": str(e), "items": [], "total": 0})

    def _api_kira_activity_dismiss(self, body: dict):
        """POST /api/kira/activity-feed/dismiss — Item im Drawer ausblenden."""
