    def _api_lexware_status(self):
        """GET /api/lexware/status"""
        db = get_db()
        try:
            last_sync = db.execute("SELECT value FROM lexware_config WHERE key='last_sync_ts'").fetchone()
            n_belege  = db.execute("SELECT COUNT(*) FROM lexware_belege").fetchone()[0]
            n_kontakte = db.execute("SELECT COUNT(*) FROM lexware_kontakte").fetchone()[0]
            n_pruef   = db.execute("SELECT COUNT(*) FROM eingangsbelege_pruefqueue WHERE status='zu_pruefen'").fetchone()[0]
        except Exception:
            last_sync = None; n_belege = 0; n_kontakte = 0; n_pruef = 0
        finally:
            db.close()
        try:
            cfg = json.loads((SCRIPTS_DIR / "config.json").read_text('utf-8'))
        except Exception:
            cfg = {}
        lex_cfg = cfg.get("lexware", {})
        self._json({
            "status": lex_cfg.get("status", "nicht_gebucht"),
            "has_key": bool(lex_cfg.get("api_key", "").strip()),
            "last_sync_ts": (last_sync[0] if last_sync else None),
            "n_belege": n_belege, "n_kontakte": n_kontakte, "n_pruef": n_pruef,
        })

    def _api_lexware_beleg(self, lex_id):
        """GET /api/lexware/beleg/{id} — DB-Daten + Live-Detail von Lexware API"""
        db = get_db()
        try:
            row = db.execute("SELECT * FROM lexware_belege WHERE lexware_id=?", (lex_id,)).fetchone()
            if not row:
                self._json({"error": "Nicht gefunden"}, 404)
                return
            d = dict(row)
            if d.get("payload_json"):
                try: d["payload"] = json.loads(d["payload_json"])
                except Exception: pass
            # Live-Detail von Lexware API abrufen (Positionen, Zahlungen etc.)
            try:
                from lexware_client import LexwareClient
                cfg = json.loads((SCRIPTS_DIR / "config.json").read_text("utf-8"))
                api_key = cfg.get("lexware", {}).get("api_key", "")
                if api_key:
                    client = LexwareClient(api_key)
                    vtype = d.get("typ", "invoice")
                    detail = client.get_voucher(lex_id, vtype)
                    d["detail"] = detail
                    # Zugehoerige Belege (relatedVouchers)
                    related = detail.get("relatedVouchers", [])
                    if related:
                        d["related_vouchers"] = related
                    # Zahlungen (paymentConditions + shippingConditions)
                    if detail.get("paymentConditions"):
                        d["payment_conditions"] = detail["paymentConditions"]
                    # Positionen (lineItems)
                    if detail.get("lineItems"):
                        d["line_items"] = detail["lineItems"]
                    # Steuern (taxAmounts)
                    if detail.get("taxAmounts"):
                        d["tax_amounts"] = detail["taxAmounts"]
                    # totalPrice (Netto/Brutto/Steuer)
                    if detail.get("totalPrice"):
                        d["total_price"] = detail["totalPrice"]
                    # Skonto-Daten in DB persistieren (fuer Kira-Analysen)
                    _pc = detail.get("paymentConditions", {})
                    _dc = _pc.get("paymentDiscountConditions", {})
                    if _dc.get("discountPercentage"):
                        try:
                            from datetime import datetime as _dt, timedelta as _td
                            _sp = _dc.get("discountPercentage", 0)
                            _st = _dc.get("discountRange", 0)
                            _brutto = (detail.get("totalPrice") or {}).get("totalGrossAmount", d.get("brutto", 0))
                            _sb = round(float(_brutto) * float(_sp) / 100, 2)
                            _bd = (detail.get("voucherDate") or d.get("datum", ""))[:10]
                            _sf = ""
                            if _bd and _st:
                                _sf = (_dt.strptime(_bd, "%Y-%m-%d") + _td(days=_st)).strftime("%Y-%m-%d")
                            db.execute("""UPDATE lexware_belege SET skonto_prozent=?, skonto_tage=?,
                                skonto_frist=?, skonto_betrag=? WHERE lexware_id=?""",
                                (_sp, _st, _sf, _sb, lex_id))
                            db.commit()
                        except Exception:
                            pass
            except Exception as e:
                d["detail_error"] = str(e)
            # Kontaktdaten nachladen (Adresse, E-Mail, Kundennummer)
            contact_id = d.get("kontakt_id") or ""
            if not contact_id and d.get("detail"):
                contact_id = d["detail"].get("contactId", "")
            if contact_id:
                try:
                    krow = db.execute(
                        "SELECT name, email, adresse_json, payload_json FROM lexware_kontakte WHERE lexware_id=?",
                        (contact_id,)
                    ).fetchone()
                    if krow:
                        kontakt = {"name": krow[0] or "", "email": krow[1] or ""}
                        if krow[2]:
                            try: kontakt["adresse"] = json.loads(krow[2])
                            except Exception: pass
                        if krow[3]:
                            try:
                                kpl = json.loads(krow[3])
                                # Rollen (Kundennummer etc.)
                                roles = kpl.get("roles", {})
                                cust = roles.get("customer", {})
                                if cust.get("number"):
                                    kontakt["kundennummer"] = cust["number"]
                                # E-Mail-Adressen
                                emails = kpl.get("emailAddresses", {})
                                if emails.get("business"):
                                    kontakt["email_business"] = emails["business"]
                                elif emails.get("office"):
                                    kontakt["email_business"] = emails["office"]
                                # Telefon
                                phones = kpl.get("phoneNumbers", {})
                                if phones.get("business"):
                                    kontakt["telefon"] = phones["business"]
                                elif phones.get("mobile"):
                                    kontakt["telefon"] = phones["mobile"]
                                # Billing-Adresse aus payload
                                addrs = kpl.get("addresses", {})
                                billing = addrs.get("billing", [])
                                if billing and len(billing) > 0:
                                    ba = billing[0]
                                    kontakt["adresse_billing"] = {
                                        "strasse": ba.get("street", ""),
                                        "plz": ba.get("zip", ""),
                                        "ort": ba.get("city", ""),
                                        "land": ba.get("countryCode", "DE"),
                                    }
                            except Exception:
                                pass
                        d["kontakt"] = kontakt
                except Exception:
                    pass
            self._json(d)
        finally:
            db.close()

